namespace BlazorApp.Services;

public record Notification(int Id, string Message, DateTime Timestamp);

public class NotificationService
{
    private int _nextId = 1;
    private readonly List<Notification> _notifications = new();
    private readonly Lock _lock = new();

    public NotificationService()
    {
        // Seed with initial fake data.
        _notifications.Add(new(NextId(), "Welcome to the notification center!", DateTime.UtcNow.AddMinutes(-30)));
        _notifications.Add(new(NextId(), "Your profile was updated successfully.", DateTime.UtcNow.AddMinutes(-15)));
        _notifications.Add(new(NextId(), "New comment on your post.", DateTime.UtcNow.AddMinutes(-5)));
    }

    /// <summary>Returns all notifications.</summary>
    public Task<List<Notification>> GetNotificationsAsync()
    {
        lock (_lock)
        {
            return Task.FromResult(_notifications.ToList());
        }
    }

    /// <summary>Returns only notifications newer than the given id.</summary>
    public Task<List<Notification>> GetNotificationsSinceAsync(int lastSeenId)
    {
        lock (_lock)
        {
            return Task.FromResult(
                _notifications.Where(n => n.Id > lastSeenId).ToList());
        }
    }

    /// <summary>Simulates an incoming notification (called by the background loop for demo purposes).</summary>
    public Notification AddRandom()
    {
        string[] samples =
        [
            "Server deployment completed.",
            "Disk usage exceeded 80%.",
            "New user signed up.",
            "Backup finished successfully.",
            "Security scan passed.",
            "Payment received.",
            "Scheduled maintenance in 1 hour.",
        ];

        var message = samples[Random.Shared.Next(samples.Length)];
        var notification = new Notification(NextId(), message, DateTime.UtcNow);

        lock (_lock)
        {
            _notifications.Add(notification);
        }

        return notification;
    }

    private int NextId() => Interlocked.Increment(ref _nextId);
}

