@page "/notifications"
@rendermode InteractiveServer
@implements IDisposable
@inject BlazorApp.Services.NotificationService NotificationService

<PageTitle>Notifications</PageTitle>

<h1>Notifications</h1>

@if (notifications is null)
{
    <p><em>Loading...</em></p>
}
else
{
    <p>
        <span class="badge bg-primary rounded-pill">@notifications.Count</span>
        notification@(notifications.Count == 1 ? "" : "s")
    </p>

    <ul class="list-group">
        @foreach (var n in notifications.OrderByDescending(x => x.Timestamp))
        {
            <li class="list-group-item d-flex justify-content-between align-items-start">
                <div>@n.Message</div>
                <small class="text-muted">@n.Timestamp.ToString("HH:mm:ss")</small>
            </li>
        }
    </ul>
}

@code {
    [PersistentState]
    public List<BlazorApp.Services.Notification>? notifications { get; set; }

    private CancellationTokenSource? _cts;

    protected override async Task OnInitializedAsync()
    {
        // ??= ensures we only fetch when state wasn't restored from prerender.
        notifications ??= await NotificationService.GetNotificationsAsync();
    }

    protected override void OnAfterRender(bool firstRender)
    {
        if (firstRender)
        {
            // OnAfterRender is never called during prerender, so the polling
            // loop only starts once the page is live and interactive.
            _cts = new CancellationTokenSource();
            _ = PollForNotificationsAsync(_cts.Token);
        }
    }

    private async Task PollForNotificationsAsync(CancellationToken ct)
    {
        while (!ct.IsCancellationRequested)
        {
            try
            {
                await Task.Delay(TimeSpan.FromSeconds(5), ct);
            }
            catch (OperationCanceledException)
            {
                break;
            }

            // Simulate a new notification arriving on the server side.
            NotificationService.AddRandom();

            var lastId = notifications?.Count > 0
                ? notifications.Max(n => n.Id)
                : 0;

            var newer = await NotificationService.GetNotificationsSinceAsync(lastId);

            if (newer.Count > 0)
            {
                notifications ??= new();
                notifications.AddRange(newer);
                await InvokeAsync(StateHasChanged);
            }
        }
    }

    public void Dispose()
    {
        // Cancel the polling loop so there are no leaked tasks.
        _cts?.Cancel();
        _cts?.Dispose();
    }
}

